{
  "day": "1",
  "heading": "Drive from Dehradun to Kotgaon",
  "sub_heading": "Drive Distance: 195 km | Duration: 10-11 hours | Pick up point for Indiahikes trekkers: Asli Pappu Da Dhaba, Dehradun | Pick up Time: 6.30 am | Location of Indiahikes basecamp: Kotgaon",
  "details": "Drive from Dehradun to Kotgaon. The cost is Rs.1200/- (additional 5% GST) per trekker (one-way). Pick-up time: 6.30 am. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Kotgaon to Taluka drive then Taluka to Chilurgad trek",
  "sub_heading": "Drive Distance: 12 km | Drive Duration: 1-hour drive\nTrek Distance: 11 km trek | Trek Duration: 7-8 hour trek | Altitude gain: 6,520 ft to 8,160 ft",
  "details": ""
}

{
  "day": "3",
  "heading": "Chilurgad to Devsu Thach",
  "sub_heading": "Trek distance: 6 km | Duration: 4-5 hours | Altitude gain: 8,160 ft to 9,795 feet",
  "details": ""
}

{
  "day": "4",
  "heading": "Devsu Thach to Ruinsara Tal",
  "sub_heading": "Trek Distance: 10 km | Trek Duration: 4-5 hours | Altitude gain: 9,795 ft to 11,715 ft",
  "details": ""
}

{
  "day": "5",
  "heading": "Ruinsara Tal to Thanga",
  "sub_heading": "Trek distance: 3 km | Duration: 3 hours | Altitude gain: 11,715 ft to 13,080 ft",
  "details": ""
}

{
  "day": "6",
  "heading": "Thanga to Advanced base camp via Odari (Bali Pass Base Camp)",
  "sub_heading": "Trek distance: 5 km | Duration: 5-6 hours | Altitude gain: 13,080 ft to 15,100 ft",
  "details": ""
}

{
  "day": "7",
  "heading": "Advance Base Camp to Lower Damini via Bali Pass",
  "sub_heading": "Trek distance: 14 km | Duration: 9-10 hours | Altitude loss: 15,100 ft to 10,080 feet via 16,207 feet (Bali pass)",
  "details": ""
}

{
  "day": "8",
  "heading": "Lower Damini to Janakichatti to Dehradun",
  "sub_heading": "Trek distance: 6 km | Trek Duration: 1 hour\nDrive Distance: 169 km | Driving time: 8 hours | Altitude loss: 10,080 ft to 8,270 ft",
  "details": "Please note: The distance between campsites may vary by 100 meters depending the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons.\nDrive from Janakichatti to Dehradun. The cost is Rs.1400/- (additional 5% GST) per trekker (one-way). Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "9",
  "heading": "Buffer Day",
  "sub_heading": "",
  "details": "If Buffer day is used, trekkers will have to pay Rs 2100 +5% GST. The money will be collected by the Trek Leader only if we use the buffer day. This depends completely on the weather conditions on the trek and the call will be taken by the trek leader.\nYou’ll be back in Dehradun by 8 pm. Please factor in the buffer day in your travel plans – book your onward journey from Dehradun only after 9 pm on Day 9."
}
